/**
 * Unified HTTP System
 * Zero-copy HTTP pipeline with reactor pattern
 */

import { HTTPServer } from './server';
import { HTTPRouter } from './router';
import { HTTPResponseBuilder } from './response';
import { HTTPHeaders } from './headers';
import { QueryParser } from './query';
import {
  HTTPRequest,
  HTTPResponse,
  HTTPServerOptions,
  RouteHandler,
  ServerStatistics,
} from './types';

export class HTTPSystem {
  private server: HTTPServer;
  private router: HTTPRouter;
  private headers: HTTPHeaders;
  private queryParser: typeof QueryParser = QueryParser;

  constructor(options?: HTTPServerOptions) {
    this.server = new HTTPServer(options);
    this.router = new HTTPRouter();
    this.headers = new HTTPHeaders();
  }

  // ============== Server ==============

  /**
   * Serve HTTP server
   */
  async serve(): Promise<void> {
    return this.server.serve(async (req: HTTPRequest) => {
      try {
        // Match route
        const match = this.router.match(req);

        if (!match) {
          return new HTTPResponseBuilder()
            .status(404)
            .json({ error: 'Route not found' })
            .build();
        }

        // Add params to request
        req.params = match.params;

        // Execute handler
        const response = await match.handler(req, {
          statusCode: 200,
          headers: {},
        });

        return response;
      } catch (error) {
        return new HTTPResponseBuilder()
          .status(500)
          .json({ error: error instanceof Error ? error.message : 'Internal server error' })
          .build();
      }
    });
  }

  /**
   * Stop server
   */
  async stop(): Promise<void> {
    return this.server.stop();
  }

  /**
   * Check if server is running
   */
  isRunning(): boolean {
    return this.server.isServerRunning();
  }

  /**
   * Get server info
   */
  getServerInfo() {
    return this.server.getServerInfo();
  }

  // ============== Routing ==============

  /**
   * Register route
   */
  route(
    method: string | string[],
    pattern: string,
    handler: RouteHandler
  ): HTTPSystem {
    this.router.route(method, pattern, handler);
    return this;

# FreeLang v4 Input Validation & Security

**8가지 입력 검증 및 보안 기법을 통합한 완벽한 보안 모듈**

[![License: MIT](https://img.shields.io/badge/License-MIT-yellow.svg)](https://opensource.org/licenses/MIT)
![Tests](https://img.shields.io/badge/Tests-72%2B-brightgreen)
![Coverage](https://img.shields.io/badge/Coverage-100%25-brightgreen)

## 📋 개요

이 모듈은 웹 애플리케이션의 입력 데이터를 검증하고 보안 위협으로부터 보호합니다. **8가지 산업 표준 보안 기법**을 제공합니다.

### 검증 기법 (5개)

| # | 기법 | 목적 | 예제 |
|---|------|------|------|
| 1️⃣ | **Email** | RFC 5322 준수 이메일 검증 | `user@example.com` ✅ |
| 2️⃣ | **Phone** | 국가별 전화번호 검증 | `010-1234-5678` (KR) ✅ |
| 3️⃣ | **URL** | RFC 3986 준수 URL 검증 | `https://example.com` ✅ |
| 4️⃣ | **Credit Card** | Luhn 알고리즘 카드 검증 | `4111111111111111` ✅ |
| 5️⃣ | **IP Address** | IPv4/IPv6 주소 검증 | `192.168.1.1` ✅ |

### 보안 기법 (3개)

| # | 기법 | 목적 | 방어 |
|---|------|------|------|
| 6️⃣ | **SQL Injection** | SQL 인젝션 방지 | `' OR '1'='1` ❌ |
| 7️⃣ | **XSS** | 크로스사이트 스크립팅 방지 | `<script>alert(1)</script>` ❌ |
| 8️⃣ | **CSRF Token** | 크로스사이트 요청 위조 방지 | 토큰 기반 검증 ✅ |

## 🚀 빠른 시작

### 설치

```bash
npm install freelang-v4-input-validation
# 또는
kpm install freelang-v4-input-validation
```

### 기본 사용법

```typescript
import { InputValidator } from 'freelang-v4-input-validation';

const validator = new InputValidator();

// Email 검증
const emailResult = validator.validateEmail('user@example.com');
console.log(emailResult.valid); // true

// SQL Injection 방지
const sqlSafe = validator.sanitizeSQL("O'Brien");
console.log(sqlSafe); // O''Brien

// XSS 방지
const xssSafe = validator.sanitizeXSS('<script>alert(1)</script>');
console.log(xssSafe); // &lt;script&gt;alert(1)&lt;/script&gt;

// CSRF 토큰
const token = validator.csrf.generate('session-123');
console.log(token); // 임의의 토큰
```

## 📚 상세 사용법

### 1. Email 검증

```typescript
const { valid, errors, sanitized } = validator.validateEmail('user@example.com');

if (valid) {
  console.log(`Email OK: ${sanitized}`); // user@example.com
} else {
  console.log(`Errors: ${errors}`);
}
```

