/**
 * 성능 최적화 통합 테스트 (50개 케이스)
 */

import { IndexManager, QueryPlanner, QueryCache, QueryStats } from '../src/index';

describe('Query Performance Module', () => {
  let mockDb: any;
  let indexManager: IndexManager;
  let queryPlanner: QueryPlanner;
  let queryCache: QueryCache;
  let queryStats: QueryStats;

  beforeAll(() => {
    mockDb = {
      exec: jest.fn(),
      run: jest.fn(() => ({ changes: 1 })),
      query: jest.fn(() => ({ count: 1000 })),
      queryAll: jest.fn(() => [
        { id: 1, name: 'Alice', email: 'alice@example.com' },
        { id: 2, name: 'Bob', email: 'bob@example.com' }
      ])
    };

    indexManager = new IndexManager(mockDb);
    queryPlanner = new QueryPlanner(mockDb, indexManager);
    queryCache = new QueryCache(100);
    queryStats = new QueryStats(1000);
  });

  describe('Indexing (12 cases)', () => {
    it('should create single column index', () => {
      const idx = indexManager.createIndex('users', ['email']);
      expect(idx.name).toContain('idx_users_email');
      expect(idx.unique).toBe(false);
    });

    it('should create unique index', () => {
      const idx = indexManager.createIndex('users', ['email'], { unique: true });
      expect(idx.unique).toBe(true);
    });

    it('should create composite index', () => {
      const idx = indexManager.createCompositeIndex('orders', ['user_id', 'created_at']);
      expect(idx.type).toBe('COMPOSITE');
    });

    it('should drop index', () => {
      indexManager.createIndex('users', ['name']);
      indexManager.dropIndex('idx_users_name');
      expect(mockDb.exec).toHaveBeenCalledWith(expect.stringContaining('DROP'));
    });

    it('should track index usage', () => {
      indexManager.createIndex('users', ['id']);
      indexManager.trackIndexUse('idx_users_id');
      expect(indexManager.getIndexStats('idx_users_id')).toBeDefined();
    });

    it('should track index scans', () => {
      indexManager.createIndex('users', ['status']);
      indexManager.trackIndexScan('idx_users_status');
    });

    it('should list all indexes', () => {
      const indexes = indexManager.listAllIndexes();
      expect(Array.isArray(indexes)).toBe(true);
    });

    it('should estimate cardinality', () => {
      const idx = indexManager.createIndex('users', ['department']);
      expect(idx.cardinality).toBeGreaterThanOrEqual(0);
    });

    it('should get index efficiency', () => {
      indexManager.createIndex('users', ['region']);
      const efficiency = indexManager.getIndexEfficiency('idx_users_region');
      expect(efficiency).toBeGreaterThanOrEqual(0);
      expect(efficiency).toBeLessThanOrEqual(100);
    });

    it('should recommend indexes for WHERE clause', () => {
      const advice = indexManager.analyzeAndRecommend('SELECT * FROM users WHERE email = ?');
      expect(Array.isArray(advice)).toBe(true);
    });

    it('should recommend composite indexes', () => {
      const advice = indexManager.analyzeAndRecommend(
        'SELECT * FROM orders WHERE user_id = ? AND status = ?'
      );
      expect(advice.length).toBeGreaterThanOrEqual(0);
    });

    it('should prioritize high-impact indexes', () => {
      const advice = indexManager.analyzeAndRecommend('SELECT * FROM users WHERE email = ?');
      if (advice.length > 0) {
        expect(['HIGH', 'MEDIUM', 'LOW']).toContain(advice[0].priority);
      }
    });
  });

  describe('Query Planner (10 cases)', () => {
    it('should analyze SELECT query', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users WHERE id = 1');
      expect(plan.cost).toBeGreaterThan(0);
      expect(plan.cost).toBeLessThanOrEqual(100);
    });

    it('should estimate row count', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users');
      expect(plan.rows).toBeGreaterThan(0);
    });

    it('should generate operations', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users');
      expect(plan.operations.length).toBeGreaterThan(0);
    });

    it('should identify SCAN operations', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users');
      const hasSeek = plan.operations.some(op => op.type === 'SEEK' || op.type === 'SCAN');
      expect(hasSeek).toBe(true);
    });

    it('should add FILTER operations for WHERE', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users WHERE status = ?');
      expect(plan.operations.length).toBeGreaterThan(0);
    });

    it('should generate query explanation', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users');
      expect(plan.explanation).toBeTruthy();
    });

    it('should cache query plans', () => {
      queryPlanner.analyze('SELECT * FROM orders');
      const size1 = queryPlanner.getCacheSize();
      queryPlanner.analyze('SELECT * FROM orders');
      const size2 = queryPlanner.getCacheSize();
      expect(size2).toBeLessThanOrEqual(size1 + 1);
    });

    it('should clear plan cache', () => {
      queryPlanner.analyze('SELECT * FROM users');
      queryPlanner.clearCache();
      expect(queryPlanner.getCacheSize()).toBe(0);
    });

    it('should handle complex WHERE clauses', () => {
      const plan = queryPlanner.analyze(
        'SELECT * FROM users WHERE age > 18 AND city = ? AND status = ?'
      );
      expect(plan.cost).toBeGreaterThan(0);
    });

    it('should recognize ORDER BY in plan', () => {
      const plan = queryPlanner.analyze('SELECT * FROM users ORDER BY created_at DESC');
      expect(plan.explanation).toBeTruthy();
    });
  });

  describe('Query Cache (14 cases)', () => {
    it('should cache query results', async () => {
      const result = await queryCache.execute(
        'SELECT * FROM users WHERE id = 1',
        [1],
        { db: mockDb }
      );
      expect(result).toBeDefined();
    });

    it('should return cached results', async () => {
      const result1 = await queryCache.execute('SELECT * FROM users', [], { db: mockDb });
      const result2 = await queryCache.execute('SELECT * FROM users', [], { db: mockDb });
      expect(result1).toEqual(result2);
    });

    it('should track cache hits', async () => {
      await queryCache.execute('SELECT * FROM orders', [], { db: mockDb });
      await queryCache.execute('SELECT * FROM orders', [], { db: mockDb });
      const stats = queryCache.getStats();
      expect(stats.totalHits).toBeGreaterThan(0);
    });

    it('should track cache misses', async () => {
      const cache = new QueryCache();
      try {
        await cache.execute('SELECT * FROM test', []);
      } catch {
        // Expected miss
      }
    });

    it('should calculate hit rate', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT 1', [], { db: mockDb });
      await cache.execute('SELECT 1', [], { db: mockDb });
      const stats = cache.getStats();
      expect(stats.hitRate).toBeGreaterThan(0);
    });

    it('should respect TTL', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT * FROM users', [], { ttl: 100, db: mockDb });

      // Wait for expiration
      await new Promise(resolve => setTimeout(resolve, 150));

      // Should be a miss due to TTL
      mockDb.queryAll.mockClear();
      await cache.execute('SELECT * FROM users', [], { db: mockDb });
      expect(mockDb.queryAll).toHaveBeenCalled();
    });

    it('should implement LRU eviction', async () => {
      const cache = new QueryCache(2);
      await cache.execute('SELECT 1', [], { db: mockDb });
      await cache.execute('SELECT 2', [], { db: mockDb });
      await cache.execute('SELECT 3', [], { db: mockDb }); // Should evict first entry

      const stats = cache.getStats();
      expect(stats.evictions).toBeGreaterThanOrEqual(0);
    });

    it('should invalidate table cache', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT * FROM users', [], { db: mockDb });

      cache.invalidateTable('users');
      const stats = cache.getStats();
      expect(stats.entries).toBe(0);
    });

    it('should clear entire cache', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT * FROM users', [], { db: mockDb });
      await cache.execute('SELECT * FROM orders', [], { db: mockDb });

      cache.clear();
      const stats = cache.getStats();
      expect(stats.entries).toBe(0);
    });

    it('should track cache size', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT * FROM users', [], { db: mockDb });

      const stats = cache.getStats();
      expect(stats.size).toBeGreaterThan(0);
    });

    it('should handle different query parameters', async () => {
      const cache = new QueryCache();
      const r1 = await cache.execute('SELECT * FROM users WHERE id = ?', [1], { db: mockDb });
      const r2 = await cache.execute('SELECT * FROM users WHERE id = ?', [2], { db: mockDb });

      expect(r1).toBeDefined();
      expect(r2).toBeDefined();
    });

    it('should generate accurate stats', async () => {
      const cache = new QueryCache();
      await cache.execute('SELECT 1', [], { db: mockDb });

      const stats = cache.getStats();
      expect(stats).toHaveProperty('hitRate');
      expect(stats).toHaveProperty('totalHits');
      expect(stats).toHaveProperty('totalMisses');
    });

    it('should track eviction count', async () => {
      const cache = new QueryCache(1);
      await cache.execute('SELECT 1', [], { db: mockDb });
      await cache.execute('SELECT 2', [], { db: mockDb });

      const stats = cache.getStats();
      expect(stats.evictions).toBeGreaterThanOrEqual(0);
    });
  });

  describe('Query Statistics (8 cases)', () => {
    it('should track query execution time', () => {
      const startTime = Date.now();
      const endTime = startTime + 10;
      queryStats.track('SELECT * FROM users', startTime, endTime);

      const stat = queryStats.getQueryStats('SELECT * FROM users');
      expect(stat?.count).toBe(1);
    });

    it('should calculate average time', () => {
      queryStats.track('SELECT * FROM orders', Date.now(), Date.now() + 5);
      queryStats.track('SELECT * FROM orders', Date.now(), Date.now() + 15);

      const stat = queryStats.getQueryStats('SELECT * FROM orders');
      expect(stat?.avgTime).toBeGreaterThan(0);
    });

    it('should track min/max times', () => {
      queryStats.track('SELECT * FROM test', Date.now(), Date.now() + 5);
      queryStats.track('SELECT * FROM test', Date.now(), Date.now() + 20);

      const stat = queryStats.getQueryStats('SELECT * FROM test');
      expect(stat?.minTime).toBeLessThan(stat?.maxTime || 0);
    });

    it('should identify slow queries', () => {
      queryStats.track('SELECT * FROM slow', Date.now(), Date.now() + 5000);

      const slowQueries = queryStats.getSlowQueries();
      expect(slowQueries.length).toBeGreaterThan(0);
    });

    it('should generate performance report', () => {
      queryStats.track('SELECT 1', Date.now(), Date.now() + 10);

      const report = queryStats.generateReport();
      expect(report.totalQueries).toBeGreaterThan(0);
      expect(report.avgExecutionTime).toBeGreaterThanOrEqual(0);
    });

    it('should calculate percentile response times', () => {
      for (let i = 0; i < 100; i++) {
        queryStats.track('SELECT 1', Date.now(), Date.now() + i);
      }

      const p95 = queryStats.getP95ResponseTime();
      const p99 = queryStats.getP99ResponseTime();

      expect(p95).toBeGreaterThanOrEqual(0);
      expect(p99).toBeGreaterThanOrEqual(p95);
    });

    it('should track cache hit rate', () => {
      queryStats.track('SELECT * FROM cache_test', Date.now(), Date.now() + 5, true);
      queryStats.track('SELECT * FROM cache_test', Date.now(), Date.now() + 5, false);

      const stat = queryStats.getQueryStats('SELECT * FROM cache_test');
      expect(stat?.hitRate).toBeGreaterThan(0);
    });

    it('should record errors', () => {
      queryStats.recordError('SELECT * FROM error_test');
      queryStats.recordError('SELECT * FROM error_test');

      const stat = queryStats.getQueryStats('SELECT * FROM error_test');
      expect(stat?.errors).toBe(2);
    });
  });

  describe('Integration (6 cases)', () => {
    it('should work together: Index + Planner', () => {
      indexManager.createIndex('users', ['email']);
      const plan = queryPlanner.analyze('SELECT * FROM users WHERE email = ?');

      expect(plan.cost).toBeLessThan(100);
    });

    it('should work together: Cache + Stats', async () => {
      const sql = 'SELECT * FROM users';
      const start = Date.now();
      await queryCache.execute(sql, [], { db: mockDb });
      const end = Date.now();

      queryStats.track(sql, start, end);

      const stat = queryStats.getQueryStats(sql);
      expect(stat?.count).toBe(1);
    });

    it('should coordinate all components', () => {
      indexManager.createIndex('orders', ['user_id']);
      const plan = queryPlanner.analyze('SELECT * FROM orders WHERE user_id = ?');

      expect(plan).toBeDefined();
      expect(plan.cost).toBeGreaterThan(0);
    });

    it('should provide complete performance insights', async () => {
      await queryCache.execute('SELECT 1', [], { db: mockDb });
      queryStats.track('SELECT 1', Date.now(), Date.now() + 5);

      const report = queryStats.generateReport();
      const cacheStats = queryCache.getStats();

      expect(report).toBeDefined();
      expect(cacheStats).toBeDefined();
    });

    it('should handle multiple concurrent operations', async () => {
      const promises = [];

      for (let i = 0; i < 10; i++) {
        promises.push(
          queryCache.execute(`SELECT ${i}`, [], { db: mockDb })
        );
      }

      const results = await Promise.all(promises);
      expect(results.length).toBe(10);
    });

    it('should optimize end-to-end query execution', async () => {
      // Create index
      indexManager.createIndex('users', ['id']);

      // Plan query
      const plan = queryPlanner.analyze('SELECT * FROM users WHERE id = 1');

      // Execute with cache
      const result = await queryCache.execute(
        'SELECT * FROM users WHERE id = 1',
        [1],
        { db: mockDb }
      );

      // Track stats
      queryStats.track('SELECT * FROM users WHERE id = 1', Date.now(), Date.now() + 5);

      expect(result).toBeDefined();
      expect(plan.cost).toBeLessThan(100);
    });
  });
});

